class Solution:
    def kthCharacter(self, k: int, operations: List[int]) -> str:
        word = "a"
        for op in operations:
            if op == 0:
                word += word
            else:
                new_word = ""
                for c in word:
                    if c == 'z':
                        new_word += 'a'
                    else:
                        new_word += chr(ord(c) + 1)
                word += new_word
        return word[k - 1]
```
